
"use client";

import { useMemo, useState } from "react";

type Venue = {
  id: string;
  name: string;
  sport_type: string;
  formatted_address: string;
  rating?: number;
  website_uri?: string;
  google_maps_uri?: string;
  ai_summary?: string;
};

const PAGE_SIZE = 9;

export default function VenueFinder() {
  const [city, setCity] = useState("");
  const [sport, setSport] = useState("");
  const [loading, setLoading] = useState(false);

  const [venues, setVenues] = useState<Venue[]>([]);
  const [selectedSport, setSelectedSport] = useState("All Sports");
  const [page, setPage] = useState(1);

  async function searchVenues() {
    if (!city) return;

    setLoading(true);

    try {
      const response = await fetch(
        "http://localhost:8000/venues/search",
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            "city":city,
            "sports":sport,
            "include_ai_summary": true,
            "ai_categorize":true,
            "max_results": 100,
          }),
        }
      );

      const data = await response.json();

      setVenues(data);
      setPage(1);
    } catch (error) {
      console.error(error);
    }

    setLoading(false);
  }

  const sports = useMemo(() => {
    const unique = [...new Set(venues.map(v => v.sport_type))];
    return ["All Sports", ...unique];
  }, [venues]);

  const filteredVenues = useMemo(() => {
    if (selectedSport === "All Sports")
      return venues;

    return venues.filter(
      v => v.sport_type === selectedSport
    );
  }, [venues, selectedSport]);

  const totalPages = Math.ceil(
    filteredVenues.length / PAGE_SIZE
  );

  const currentVenues = filteredVenues.slice(
    (page - 1) * PAGE_SIZE,
    page * PAGE_SIZE
  );

  function exportCSV() {
    const rows = filteredVenues.map(v => ({
      name: v.name,
      sport: v.sport_type,
      address: v.formatted_address,
      rating: v.rating,
    }));

    const csv =
      [
        Object.keys(rows[0]).join(","),
        ...rows.map(r =>
          Object.values(r).join(",")
        ),
      ].join("\n");

    const blob = new Blob([csv], {
      type: "text/csv",
    });

    const url = URL.createObjectURL(blob);

    const a = document.createElement("a");
    a.href = url;
    a.download = `${city}-venues.csv`;
    a.click();
  }

  return (
    <main className="min-h-screen bg-[#0B1120] text-white">

      {/* HERO */}

      <section className="max-w-7xl mx-auto px-6 pt-24 pb-16 text-center">

        <div className="uppercase tracking-[0.25em] text-emerald-400 text-xs font-semibold">
          Powered by OpenStreetMaps + AI
        </div>

        <h1 className="mt-6 text-6xl md:text-7xl font-black">
          Find Amazing
          <span className="text-emerald-400">
            {" "}Sports Venues
          </span>
        </h1>

        <p className="max-w-2xl mx-auto mt-6 text-slate-400">
          Discover stadiums, courts, pitches and
          sports facilities with AI powered
          recommendations.
        </p>

        {/* SEARCH */}

        <div className="mt-12 bg-slate-900 border border-slate-800 rounded-3xl p-5 grid lg:grid-cols-3 gap-4">

          <input
            value={city}
            onChange={(e) =>
              setCity(e.target.value)
            }
            placeholder="City"
            className="bg-slate-800 rounded-xl p-4 outline-none"
          />

          <input
            value={sport}
            onChange={(e) =>
              setSport(e.target.value)
            }
            placeholder="Sport"
            className="bg-slate-800 rounded-xl p-4 outline-none"
          />

          <button
            onClick={searchVenues}
            className="bg-emerald-500 hover:bg-emerald-400 text-black rounded-xl font-bold"
          >
            Search Venues
          </button>
        </div>
      </section>

      {/* CONTENT */}

      <section className="max-w-7xl mx-auto px-6 pb-24">

        <div className="grid lg:grid-cols-[280px_1fr] gap-8">

          {/* SIDEBAR */}

          <aside className="bg-slate-900 border border-slate-800 rounded-3xl p-6 h-fit">

            <h3 className="font-bold text-xl">
              Filters
            </h3>

            <div className="mt-6">
              <label className="text-slate-400 text-sm">
                Sport
              </label>

              <select
                value={selectedSport}
                onChange={(e) =>
                  setSelectedSport(e.target.value)
                }
                className="mt-2 w-full bg-slate-800 rounded-xl p-3"
              >
                {sports.map(s => (
                  <option key={s}>{s}</option>
                ))}
              </select>
            </div>

            <button
              onClick={exportCSV}
              className="w-full mt-6 border border-slate-700 rounded-xl p-3"
            >
              Export CSV
            </button>
          </aside>

          {/* RESULTS */}

          <div>

            <div className="flex justify-between items-center mb-8">

              <h2 className="text-3xl font-bold">
                {filteredVenues.length} Venues Found
              </h2>

              <span className="text-slate-400">
                Page {page} of {Math.max(1,totalPages)}
              </span>

            </div>

            {loading && (
              <div className="text-center py-20">
                Loading venues...
              </div>
            )}

            <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-6">

              {currentVenues.map((venue) => (
                <div
                  key={venue.id}
                  className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden"
                >

                  <div className="h-52 bg-gradient-to-br from-slate-700 to-slate-900" />

                  <div className="p-5">

                    <span className="inline-flex bg-emerald-500/10 text-emerald-400 rounded-full px-3 py-1 text-xs">
                      {venue.sport_type}
                    </span>

                    <h3 className="mt-4 text-xl font-bold">
                      {venue.name}
                    </h3>

                    <div className="mt-3">
                      ⭐ {venue.rating || "N/A"}
                    </div>

                    <div className="mt-2 text-slate-400">
                      📍 {venue.formatted_address}
                    </div>

                    {venue.ai_summary && (
                      <div className="mt-4 bg-blue-500/10 border border-blue-500/20 rounded-xl p-3 text-sm text-slate-300">
                        ✨ {venue.ai_summary}
                      </div>
                    )}

                    <div className="flex gap-2 mt-5">

                      {venue.website_uri && (
                        <a
                          href={venue.website_uri}
                          target="_blank"
                          className="flex-1 bg-emerald-500 text-black text-center rounded-lg py-2"
                        >
                          Website
                        </a>
                      )}

                      {venue.google_maps_uri && (
                        <a
                          href={venue.google_maps_uri}
                          target="_blank"
                          className="flex-1 border border-slate-700 text-center rounded-lg py-2"
                        >
                          Maps
                        </a>
                      )}

                    </div>

                  </div>

                </div>
              ))}

            </div>

            {/* PAGINATION */}

            {totalPages > 1 && (
              <div className="flex justify-center gap-2 mt-12">

                <button
                  disabled={page === 1}
                  onClick={() =>
                    setPage(page - 1)
                  }
                  className="px-4 py-2 border border-slate-700 rounded-lg"
                >
                  Prev
                </button>

                <button
                  disabled={page === totalPages}
                  onClick={() =>
                    setPage(page + 1)
                  }
                  className="px-4 py-2 border border-slate-700 rounded-lg"
                >
                  Next
                </button>

              </div>
            )}

          </div>

        </div>

      </section>

    </main>
  );
}

